const body = $input.first().json.body || $input.first().json;
const query = body.query || body.q || '';
const sessionKey = body.session_id || body.sessionKey || `anon_${Date.now()}_${Math.random().toString(36).slice(2,8)}`;
const startTime = Date.now();

return [{
  json: {
    query: query.trim(),
    sessionKey,
    startTime,
    clientMeta: {
      userAgent: $input.first().json.headers?.['user-agent'] || 'unknown',
      timestamp: new Date().toISOString()
    }
  }
}];

const data = $input.first().json;
const query = data.query.toLowerCase();

const cotacaoPatterns = [
  /\b(preco|cotacao|quanto|valor|custa|arroba|saca)\b.*\b(boi|vaca|bezerro|soja|milho|cafe|leite|trigo|algodao)\b/i,
  /\b(boi|vaca|bezerro|soja|milho|cafe|leite|trigo|algodao)\b.*\b(preco|cotacao|quanto|valor|custa|arroba|saca)\b/i,
  /\b(boi gordo|arroba|indicador|cepea)\b/i
];

const climaPatterns = [
  /\b(tempo|clima|previsao|chuva|chuvas|temperatura|sol|nublado|frio|calor|geada|seca|umidade)\b/i,
  /\b(chover|chove|vai chover)\b.*\b(hoje|amanha|semana|proximos dias)\b/i
];

let intent = 'geral';
let confidence = 0.6;

for (const pattern of cotacaoPatterns) {
  if (pattern.test(query)) {
    intent = 'cotacao';
    confidence = 0.95;
    break;
  }
}

if (intent === 'geral') {
  for (const pattern of climaPatterns) {
    if (pattern.test(query)) {
      intent = 'clima';
      confidence = 0.92;
      break;
    }
  }
}

return [{
  json: {
    ...data,
    intent,
    confidence
  }
}];

const data = $input.first().json;
const query = data.query.toLowerCase();

// Mapeamento de produtos
const produtos = {
  'boi gordo': 'boi_gordo', 'boi': 'boi_gordo', 'arroba': 'boi_gordo',
  'soja': 'soja', 'milho': 'milho', 'cafe': 'cafe_arabica',
  'leite': 'leite', 'trigo': 'trigo'
};

const pracas = {
  'sp': 'SP', 'ms': 'MS', 'mt': 'MT', 'go': 'GO', 'pr': 'PR', 'rs': 'RS', 'mg': 'MG', 'ba': 'BA'
};

const pracaDefault = {
  'boi_gordo': 'SP', 'soja': 'PR', 'milho': 'SP', 'cafe_arabica': 'SP', 'leite': 'MG'
};

let produto = null;
let praca = null;

for (const [key, value] of Object.entries(produtos)) {
  if (query.includes(key)) { produto = value; break; }
}
for (const [key, value] of Object.entries(pracas)) {
  if (query.includes(key)) { praca = value; break; }
}

if (!produto) produto = 'boi_gordo';
if (!praca) praca = pracaDefault[produto] || 'SP';

// Buscar cotacao no Supabase via REST API
const SUPABASE_URL = $env.SUPABASE_URL || 'https://uvrvlesjgyimspdsghmw.supabase.co';
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY || '';

let quotes = [];
let answer = '';
let sources = [];

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/quotes_latest?product=eq.${produto}&select=*`,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
    }
  });
  quotes = response;

  if (quotes && quotes.length > 0) {
    const q = quotes.find(x => x.praca === praca) || quotes[0];
    const precoFormatado = q.price ? `R$ ${parseFloat(q.price).toFixed(2)}` : 'N/D';
    const unidade = q.unit || '@';
    const dataFormatada = q.quote_date || 'hoje';
    const produtoNome = q.product ? q.product.replace('_', ' ') : produto;

    // System prompt para COTACAO
    const systemPrompt = `Voce e o FarolRural, assistente especializado em agronegocio brasileiro.

SUA MISSAO: Ensinar o produtor a ler o mercado. Nao apenas informar precos.

ESTILO DE ESCRITA:
- Texto fluido como analise de mercado profissional
- Paragrafos conectados, cada um puxando o proximo
- Explicar causa e efeito: por que o preco esta assim
- Tom de analista conversando com profissional do agro

ESTRUTURA:
1. Preco + praca + condicao + fonte (1a linha direta)
2. Contexto de mercado (oferta, demanda, custos, cambio) - 2-3 paragrafos
3. O que acompanhar (2-3 pontos em bullets)
4. Fonte e horario

PROIBIDO: comecar com 'Claro!', usar emojis, listas longas, texto robotico.`;

    const userPrompt = `Pergunta do produtor: ${data.query}

DADOS DE COTACAO:
- Produto: ${produtoNome}
- Praca: ${q.praca || praca}
- Preco: ${precoFormatado}/${unidade}
- Data: ${dataFormatada}
- Variacao dia: ${q.change_day ? `R$ ${parseFloat(q.change_day).toFixed(2)}` : 'N/D'}
- Fonte: ${q.source_url ? 'Scot Consultoria' : 'Base FarolRural'}

Gere a resposta seguindo a estrutura definida.`;

    // Chamar OpenAI
    const OPENAI_API_KEY = $env.OPENAI_API_KEY || '';

    if (OPENAI_API_KEY) {
      const aiResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.openai.com/v1/chat/completions',
        headers: {
          'Authorization': `Bearer ${OPENAI_API_KEY}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'gpt-4o-mini',
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt }
          ],
          max_tokens: 600,
          temperature: 0.3
        })
      });

      answer = aiResponse.choices?.[0]?.message?.content || `${produtoNome} em ${q.praca || praca}: ${precoFormatado}/${unidade} (${dataFormatada}).`;
    } else {
      // Fallback sem OpenAI
      answer = `${produtoNome} em ${q.praca || praca}: ${precoFormatado}/${unidade} (${dataFormatada}).\n\n`;
      if (q.change_day) {
        const variacao = parseFloat(q.change_day);
        const sinal = variacao >= 0 ? '+' : '';
        answer += `Variacao no dia: ${sinal}R$ ${variacao.toFixed(2)}/${unidade}.\n\n`;
      }
      answer += `Fonte: Scot Consultoria.`;
    }

    sources.push({ name: 'Scot Consultoria', url: q.source_url || '#', date: q.quote_date });
  } else {
    answer = `Nao encontramos cotacao para ${produto.replace('_', ' ')} em ${praca} no momento. Tente outra praca ou produto.`;
    sources.push({ name: 'Base FarolRural', url: '#' });
  }
} catch (error) {
  answer = `Erro ao buscar cotacao: ${error.message}. Tente novamente.`;
  sources.push({ name: 'Erro', url: '#' });
}

return [{
  json: {
    ...data,
    handler: 'cotacao',
    extracted: { produto, praca },
    answer,
    chips: ['Cotacao boi gordo MS', 'Cotacao soja PR', 'Indicador Cepea'],
    sources,
    rawQuotes: quotes
  }
}];

const data = $input.first().json;
const query = data.query.toLowerCase();

// Mapeamento de localizacoes
const locations = {
  'sao paulo': { lat: -23.55, lon: -46.63, name: 'Sao Paulo', uf: 'SP' },
  'sp': { lat: -23.55, lon: -46.63, name: 'Sao Paulo', uf: 'SP' },
  'cuiaba': { lat: -15.60, lon: -56.10, name: 'Cuiaba', uf: 'MT' },
  'sorriso': { lat: -12.55, lon: -55.71, name: 'Sorriso', uf: 'MT' },
  'campo grande': { lat: -20.44, lon: -54.65, name: 'Campo Grande', uf: 'MS' },
  'ms': { lat: -20.44, lon: -54.65, name: 'Campo Grande', uf: 'MS' },
  'goiania': { lat: -16.68, lon: -49.25, name: 'Goiania', uf: 'GO' },
  'go': { lat: -16.68, lon: -49.25, name: 'Goiania', uf: 'GO' },
  'ribeirao preto': { lat: -21.17, lon: -47.81, name: 'Ribeirao Preto', uf: 'SP' },
  'londrina': { lat: -23.31, lon: -51.16, name: 'Londrina', uf: 'PR' },
  'pr': { lat: -25.43, lon: -49.27, name: 'Curitiba', uf: 'PR' },
  'uberaba': { lat: -19.75, lon: -47.93, name: 'Uberaba', uf: 'MG' },
  'mg': { lat: -19.92, lon: -43.94, name: 'Belo Horizonte', uf: 'MG' },
  'rio verde': { lat: -17.80, lon: -50.92, name: 'Rio Verde', uf: 'GO' },
  'sinop': { lat: -11.86, lon: -55.50, name: 'Sinop', uf: 'MT' },
  'lucas do rio verde': { lat: -13.05, lon: -55.91, name: 'Lucas do Rio Verde', uf: 'MT' },
  'mt': { lat: -15.60, lon: -56.10, name: 'Cuiaba', uf: 'MT' }
};

let location = { lat: -23.55, lon: -46.63, name: 'Sao Paulo', uf: 'SP' };
for (const [key, value] of Object.entries(locations)) {
  if (query.includes(key)) { location = value; break; }
}

let answer = '';
let sources = [];
let weatherData = null;

// OpenWeather API Key
const OPENWEATHER_API_KEY = $env.OPENWEATHER_API_KEY || '';

try {
  const weatherResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.openweathermap.org/data/2.5/weather?lat=${location.lat}&lon=${location.lon}&units=metric&lang=pt_br&appid=${OPENWEATHER_API_KEY}`
  });

  weatherData = { current: weatherResponse };

  const temp = Math.round(weatherResponse.main?.temp || 0);
  const feels = Math.round(weatherResponse.main?.feels_like || 0);
  const humidity = weatherResponse.main?.humidity || 0;
  const description = weatherResponse.weather?.[0]?.description || 'tempo variavel';
  const windSpeed = Math.round((weatherResponse.wind?.speed || 0) * 3.6);
  const tempMin = Math.round(weatherResponse.main?.temp_min || 0);
  const tempMax = Math.round(weatherResponse.main?.temp_max || 0);

  // System prompt CLIMA
  const systemPrompt = `Voce e o FarolRural, assistente especializado em agronegocio brasileiro.

SUA MISSAO: Traduzir clima em impacto agricola. Ajudar o produtor a tomar decisoes.

ESTILO DE ESCRITA:
- Texto fluido com foco em impacto pratico
- Localizacao sempre clara (cidade/regiao)
- Alertas em destaque quando existirem (use emoji alerta apenas)
- Conectar previsao com operacoes de campo

ESTRUTURA:
1. Previsao direta (localizacao + condicao atual)
2. Descricao do cenario climatico
3. Alerta climatico (se houver risco)
4. Impacto agricola local (lavoura, pecuaria, operacoes)
5. Contexto recente (o que vinha acontecendo)
6. Pontos de atencao (maximo 3 bullets)
7. Fontes: OpenWeather + INMET

OBRIGATORIO:
- Sempre mencionar impacto em lavouras E pecuaria
- Destacar janelas de oportunidade ou risco
- Primeira linha direta, sem 'Claro!' ou saudacoes`;

  const userPrompt = `Pergunta do produtor: ${data.query}

DADOS CLIMATICOS ATUAIS para ${location.name} (${location.uf}):
- Temperatura: ${temp}C (sensacao ${feels}C)
- Minima/Maxima: ${tempMin}C / ${tempMax}C
- Condicao: ${description}
- Umidade: ${humidity}%
- Vento: ${windSpeed} km/h
- Coordenadas: ${location.lat}, ${location.lon}

Gere a resposta seguindo a estrutura definida. Use dados reais acima.`;

  // Chamar OpenAI
  const OPENAI_API_KEY = $env.OPENAI_API_KEY || '';

  if (OPENAI_API_KEY) {
    const aiResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': `Bearer ${OPENAI_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ],
        max_tokens: 700,
        temperature: 0.3
      })
    });

    answer = aiResponse.choices?.[0]?.message?.content || `Em ${location.name} (${location.uf}), temperatura de ${temp}C com ${description}.`;
  } else {
    answer = `Em ${location.name} (${location.uf}), temperatura de ${temp}C (sensacao de ${feels}C) com ${description}. Umidade em ${humidity}% e vento de ${windSpeed} km/h.`;
  }

  sources.push({ name: 'OpenWeather', url: 'https://openweathermap.org', date: new Date().toISOString().split('T')[0] });
} catch (error) {
  answer = `Erro ao buscar clima: ${error.message}. Tente novamente.`;
  sources.push({ name: 'Erro', url: '#' });
}

return [{
  json: {
    ...data,
    handler: 'clima',
    location,
    answer,
    chips: ['Previsao 7 dias', 'Alertas INMET', 'Clima MATOPIBA'],
    sources,
    weatherData
  }
}];

const data = $input.first().json;
const query = data.query.toLowerCase();

// Supabase config
const SUPABASE_URL = $env.SUPABASE_URL || 'https://uvrvlesjgyimspdsghmw.supabase.co';
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY || '';

let answer = '';
let sources = [];
let cards = [];
let ragContext = '';

// Keywords para categorizar a busca
const categoryMap = {
  'boi': 'pecuaria_corte', 'gado': 'pecuaria_corte', 'pecuaria': 'pecuaria_corte',
  'carne': 'pecuaria_corte', 'frigorifico': 'pecuaria_corte', 'abate': 'pecuaria_corte',
  'soja': 'graos', 'milho': 'graos', 'grao': 'graos', 'colheita': 'graos',
  'safra': 'graos', 'plantio': 'graos',
  'chuva': 'clima', 'seca': 'clima', 'tempo': 'clima', 'clima': 'clima', 'matopiba': 'clima',
  'leite': 'pecuaria_leite', 'cafe': 'cafe', 'algodao': 'fibras'
};

let targetCategory = null;
for (const [keyword, category] of Object.entries(categoryMap)) {
  if (query.includes(keyword)) {
    targetCategory = category;
    break;
  }
}

try {
  // Buscar cards relevantes
  let cardsUrl = `${SUPABASE_URL}/rest/v1/cards?status=eq.published&select=*&order=published_at.desc&limit=5`;
  if (targetCategory) {
    cardsUrl = `${SUPABASE_URL}/rest/v1/cards?status=eq.published&category=eq.${targetCategory}&select=*&order=published_at.desc&limit=3`;
  }

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: cardsUrl,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
    }
  });

  cards = response || [];

  // Se nao encontrou na categoria, busca todos
  if (cards.length === 0 && targetCategory) {
    const fallbackResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/cards?status=eq.published&select=*&order=published_at.desc&limit=5`,
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
      }
    });
    cards = fallbackResponse || [];
  }

  // Montar contexto RAG
  if (cards.length > 0) {
    ragContext = cards.map((c, i) => 
      `[${i+1}] ${c.title}\n${c.deck || ''}\n${c.body_markdown || ''}\nFonte: ${c.source_name || 'FarolRural'}`
    ).join('\n\n---\n\n');

    sources = cards.map(c => ({
      name: c.source_name || 'FarolRural',
      url: c.source_url || '#',
      date: c.published_at ? c.published_at.split('T')[0] : null
    }));
  } else {
    ragContext = 'Nenhum conteudo especifico encontrado na base de conhecimento.';
  }

  // System prompt GERAL
  const systemPrompt = `Voce e o FarolRural, assistente especializado em agronegocio brasileiro.

SUA MISSAO: Ensinar o produtor a ler o mercado. Conectar informacoes, mostrar impactos, antecipar cenarios.

ESTILO DE ESCRITA:
- Texto fluido e bem escrito como analise editorial
- Paragrafos conectados naturalmente
- Explicar o "por que" de cada movimento
- Conectar fatores: clima, cambio, graos, credito, exportacao
- Trazer informacoes que agregam valor, mesmo sem perguntar

ESTRUTURA:
1. Resposta direta ao tema
2. Contexto analitico (o que esta acontecendo e por que)
3. Conexoes com outros fatores do agro
4. Insight, risco ou oportunidade
5. Pontos de atencao (maximo 3 bullets)
6. Fontes

PROIBIDO:
- Comecar com 'Claro!' ou saudacoes
- Respostas superficiais ou apenas informativas
- Texto generico de IA
- Listas substituindo explicacao`;

  const userPrompt = `Pergunta do produtor: ${data.query}

BASE DE CONHECIMENTO FAROLRURAL:
${ragContext}

Gere uma resposta seguindo a estrutura definida. Use as informacoes da base de conhecimento para fundamentar sua analise. Se o conteudo nao cobrir exatamente a pergunta, use seu conhecimento de mercado agricola para complementar.`;

  // Chamar OpenAI
  const OPENAI_API_KEY = $env.OPENAI_API_KEY || '';

  if (OPENAI_API_KEY) {
    const aiResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': `Bearer ${OPENAI_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ],
        max_tokens: 800,
        temperature: 0.3
      })
    });

    answer = aiResponse.choices?.[0]?.message?.content || `Com base na sua pergunta sobre "${data.query}", aqui esta uma analise do cenario atual.`;
  } else {
    // Fallback sem OpenAI
    if (cards.length > 0) {
      const c = cards[0];
      answer = `${c.title}\n\n${c.deck || ''}\n\n${c.body_markdown || ''}`;
    } else {
      answer = `Com base na sua pergunta sobre "${data.query}", aqui esta uma analise do cenario atual. Configure OpenAI para respostas completas.`;
    }
  }

  if (sources.length === 0) {
    sources.push({ name: 'Base FarolRural', url: '#' });
  }

} catch (error) {
  answer = `Erro ao processar consulta: ${error.message}. Tente novamente.`;
  sources.push({ name: 'Erro', url: '#' });
}

// Gerar chips dinamicos baseados na query
const chips = [];
if (query.includes('boi') || query.includes('gado')) {
  chips.push('Cotacao boi gordo SP', 'Exportacoes de carne', 'Preco do milho');
} else if (query.includes('soja') || query.includes('grao')) {
  chips.push('Cotacao soja PR', 'Colheita MT', 'Logistica de graos');
} else {
  chips.push('Mercado de graos', 'Pecuaria de corte', 'Noticias do agro');
}

return [{
  json: {
    ...data,
    handler: 'geral',
    answer,
    chips,
    sources,
    ragCards: cards.length,
    category: targetCategory
  }
}];

const data = $input.first().json;
const timingMs = Date.now() - data.startTime;

const SUPABASE_URL = $env.SUPABASE_URL || 'https://uvrvlesjgyimspdsghmw.supabase.co';
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY || '';

let sessionId = null;

try {
  // 1. Criar search_session
  const sessionRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/search_sessions`,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify({
      session_key: data.sessionKey,
      client_meta: { source: 'n8n', version: 'v4.0' }
    })
  });

  if (Array.isArray(sessionRes) && sessionRes.length > 0) {
    sessionId = sessionRes[0].id;
  }

  if (sessionId) {
    // 2. Insert ai_outputs
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/ai_outputs`,
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        session_id: sessionId,
        query: data.query || '',
        intent: data.intent,
        answer_markdown: data.answer?.substring(0, 5000) || '',
        sources_used: data.sources || [],
        chips: data.chips || [],
        cards_returned: [],
        timing_ms: timingMs,
        token_in: 500,
        token_out: 300,
        cost_est_usd: 0.0015,
        model_used: 'gpt-4o-mini'
      })
    });

    // 3. Insert events
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/events`,
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        session_id: sessionId,
        event_type: 'search_completed',
        payload: {
          sessionKey: data.sessionKey,
          intent: data.intent,
          confidence: data.confidence,
          timingMs,
          query: data.query
        }
      })
    });
  }
} catch (err) {
  // Telemetria nao bloqueia resposta
  console.log('Telemetry error:', err.message);
}

return [{
  json: {
    success: true,
    data: {
      intent: data.intent,
      confidence: data.confidence,
      answer: data.answer,
      chips: data.chips || [],
      sources: data.sources || [],
      timingMs
    },
    meta: {
      sessionKey: data.sessionKey,
      handler: data.handler,
      version: 'v4.0'
    }
  }
}];
